"use strict";module.exports={meta:{type:"suggestion",docs:{description:"Disallow octal escape sequences in string literals",recommended:!1,url:"https://eslint.org/docs/latest/rules/no-octal-escape"},schema:[],messages:{octalEscapeSequence:"Don't use octal: '\\{{sequence}}'. Use '\\u....' instead."}},create:e=>({Literal(s){if("string"!=typeof s.value)return;const t=s.raw.match(/^(?:[^\\]|\\.)*?\\([0-3][0-7]{1,2}|[4-7][0-7]|0(?=[89])|[1-7])/su);t&&e.report({node:s,messageId:"octalEscapeSequence",data:{sequence:t[1]}})}})};